{{#css:
.map-dh {
    width:100%;
    overflow:hidden;
    margin:10px 0px;
    display:table;
    border-radius: 4px;
}

.map-dh-left {
    display:table-cell;
    vertical-align: middle;
    width:140px;
    padding:10px;
    font-weight:bold;
    font-size:16px;
    background:#7B5F44;
    color:#F2E3C6;
    text-align:center;
}

.map-dh-right {
    display:table-cell;
    vertical-align: middle;
    width:calc(100% - 100px);
    padding:10px;
    color:#cbbba4;
    background:#eee;
}

.map-dh-an {
    float: left;
    width: 120px;
    color: #848080!important;
    background: #DCCF9E;
    padding: 3px 10px;
    text-align: center;
    border-radius: 4px;
    margin:4px;
}

.map-dh-an:hover {
    background:#EAECF0;
    transition:.2s;
}

@media only screen and (max-width:759px){
    .map-dh-an {
        width:48%;
        margin:4px 1%;
    }

    .map-dh-left {
        display:block;
        width:100%;
    }

    .map-dh-right {
        display:block;
        width:100%;
    }
}
}}
